#!/usr/bin/env python3
from transformers import AutoModelForSequenceClassification, AutoTokenizer, AutoModelForCausalLM
import torch
from llama_cpp import Llama
class NLI_client():
    
    def __init__(self,model_name:str):
        self.device = torch.device("cuda") if torch.cuda.is_available() else torch.device("cpu")
        self.tokenizer = AutoTokenizer.from_pretrained(model_name)
        self.model = AutoModelForSequenceClassification.from_pretrained(model_name,device_map="auto")
    
    def run(self,premise:str, hypothesis:str):
        #print(f"Premise: {premise}")
        #print(f"Hypothesis: {hypothesis}")
        input = self.tokenizer(premise, hypothesis, truncation=True, return_tensors="pt").to(self.device)
        output = self.model(input["input_ids"].to(self.device))  # device = "cuda:0" or "cpu"
        prediction = torch.softmax(output["logits"][0], -1).tolist()
        #label_names = ["entailment", "not_entailment"]
        prediction = prediction[0]
        #prediction = {name: round(float(pred) * 100, 1) for pred, name in zip(prediction, label_names)}
        #print(f"Entailment probability: {prediction}")
        return prediction
    
class LRM_client():
    def __init__(self, name_or_path:str):
        self.model = Llama(name_or_path, n_ctx=2048)
        print("Model initialized")

    def run(self,question:str):
        output = self.model(question)
        return output

